SELECT *
FROM properties
WHERE city = 'New York';

SELECT city, AVG(estimated_value) AS avg_estimated_value
FROM properties
GROUP BY city;

SELECT auction_id, MAX(bid_amount) AS highest_bid
FROM bids
GROUP BY auction_id;

SELECT b.*
FROM bids b
JOIN (
  SELECT auction_id, MAX(bid_time) AS latest_bid_time
  FROM bids
  GROUP BY auction_id
) lb ON b.auction_id = lb.auction_id
   AND b.bid_time = lb.latest_bid_time;

Investor & Activity Analysis;

SELECT investor_id, COUNT(*) AS total_bids
FROM bids
GROUP BY investor_id;

SELECT DISTINCT investor_id
FROM bids
WHERE bid_amount > amount;

SELECT *
FROM bids
WHERE bid_time >= NOW() - INTERVAL 7 DAY;
